async function uploadSavedUrlAsTextFile() {
  const savedUrl = localStorage.getItem("savedUrl");
  if (!savedUrl) {
    alert('Please save a URL first');
    return;
  }

  const userName = 'admin';
  const password = 'uHkwV1ww82wckDyh';
  const encodedCredentials = btoa(`${userName}:${password}`);

  const fileName = 'saved-url.txt';
  const file = new File([savedUrl], fileName, { type: 'text/plain' });

  const formData = new FormData();
  formData.append('file', file);

  try {
    const response = await fetch('https://patrick-mcgrory-mitto3.zuarbase.net/api/v2/files/upload', {
      method: 'POST',
      headers: {
        'Authorization': `Basic ${encodedCredentials}`,
      },
      body: formData,
    });

    if (response.ok) {
      const data = await response.json();
      alert('File uploaded successfully');
      console.log(data);
    } else {
      throw new Error('Error uploading file');
    }
  } catch (error) {
    alert('Error uploading file');
    console.error(error);
  }
}
